const input = $('Input — user_id + channel').first().json;
const rows = $input.all();
const profile = rows.length > 0 && rows[0].json.user_id ? rows[0].json : null;

if (profile) {
  return [{ json: { action: 'proceed', profile } }];
} else {
  return [{ json: {
    action: 'onboard',
    user_id: input.user_id,
    channel: input.channel,
    display_name: input.display_name ?? 'Unknown'
  } }];
}
